select a.pur_order_date +' -'+ CAST(a.seq AS NVARCHAR) AS purOrderDateSeq ,a.pur_order_date ,a.delivery_date ,dbo.getCustomerName(a.customer_cd) as customer_name ,a.item_cd ,a.item_name ,dbo.getStorageName(a.storage_cd) as storageName ,a.qty ,a.spec ,(select sum(qty) from tb_purm_order_mst where pur_order_id = a.pur_order_id) as totQty ,0 as inQty ,a.supply_price ,case when a.in_yn = 'Y' then '입고완료'else '미입고' end inYn ,case when a.end_yn = 'Y' then '종결'else '진행중' end endYn ,case when a.mail_yn = 'Y' then '발송'else '미발송' end mailYn ,dbo.getUserName(a.manager_id) as manager_name ,a.pur_order_id from tb_purm_order_mst a where 1=1
and a.pur_order_date between #{strDate} and #{toDate}
and b.area_cd = #{areaCd}
and a.item_type_cd = #{itemTypeCd}
and a.item_cd = #{itemCd}
and a.item_name like '%' + #{itemName} + '%'
and f.customer_name like '%' + #{customerName} + '%'
and a.in_yn = #{inYn}
and a.end_yn = #{endYn}
order by a.pur_order_date desc, a.seq desc

SELECT a.pur_order_date + ' -' + CAST(a.seq AS NVARCHAR) AS purOrderDateSeq ,a.pur_order_date ,CASE WHEN COUNT(b.item_cd) = 1 THEN MIN(b.item_name) ELSE MIN(b.item_name) + ' 외 ' + CAST(COUNT(b.item_cd) - 1 AS VARCHAR) + '건' END AS item_name ,dbo.getCustomerName(a.customer_cd) AS customer_Name ,a.storage_cd ,SUM(b.qty) AS totQty ,SUM(b.in_price) AS totPrice ,sum(b.supply_Price) as supplyPrice ,a.delivery_date ,dbo.getStorageName(a.storage_cd) AS storage_name ,CASE WHEN a.end_yn = 'Y' THEN '종결' ELSE '진행중' END AS endYn ,CASE WHEN a.mail_yn = 'Y' THEN '발송' ELSE '미발송' END AS mailYn ,dbo.getUserName(a.manager_id) AS manager_name ,a.pur_order_id FROM tb_purp_order_mst a INNER JOIN tb_purp_order_item b ON a.pur_order_id = b.pur_order_id where 1=1
and a.pur_order_date between #{strDate} and #{toDate}
and b.area_cd = #{areaCd}
and a.item_cd = #{itemCd}
and b.item_name like '%' + #{itemName} + '%'
and dbo.getCustomerName(a.customer_cd) like '%' + #{customerName} + '%'
and a.end_yn = #{endYn}
GROUP BY a.pur_order_date, a.seq, a.customer_cd, a.delivery_date, a.storage_cd, a.end_yn, a.mail_yn, a.manager_id, a.pur_order_id order by a.pur_order_date desc, a.seq desc

